import { markActiveStudioSessionEnded } from "../activeStudioSession.js";
import { closeStudio } from "../agentSessionChannel.js";
import { getConfig, hasCredentials } from "../config.js";
import { positionalArgs } from "../parseArgs.js";
export async function runCloseStudio() {
    const ARGS = [
        { name: "sessionId", format: "uuid" },
        { name: "message", required: false },
    ];
    const args = positionalArgs(ARGS);
    const sessionId = args[0];
    const message = args[1];
    if (!hasCredentials()) {
        console.error("Not authenticated.");
        process.exit(1);
    }
    const config = getConfig();
    if (!config.apiKey) {
        console.error("No API key configured.");
        process.exit(1);
    }
    await closeStudio({ serviceUrl: config.serviceUrl, apiKey: config.apiKey, sessionId }, message);
    // An agent-driven close is a deliberate end: mark the record so the next open
    // silently opens fresh. This process has no poller to catch the resulting
    // session-ended event, so mark it directly.
    markActiveStudioSessionEnded(sessionId);
    process.exit(0);
}
